1	// MetadataEnricher resolves git metadata and computes transcript metrics for
2	// sessions. It consolidates all CWD/branch/project resolution and metrics
3	// computation that was previously spread across SessionDetector event handlers.
4	package services
5	
6	import (
7		"path/filepath"
8	
9		"irrlicht/core/domain/agent"
10		"irrlicht/core/domain/session"
11		"irrlicht/core/ports/outbound"
12	)
13	
14	// MetadataEnricher enriches session state with git metadata and transcript
15	// metrics. It holds references to GitResolver and MetricsCollector, which were
16	// previously fields on SessionDetector.
17	type MetadataEnricher struct {
18		git     outbound.GitResolver
19		metrics outbound.MetricsCollector
20	}
21	
22	// NewMetadataEnricher creates a MetadataEnricher with the given dependencies.
23	func NewMetadataEnricher(git outbound.GitResolver, metrics outbound.MetricsCollector) *MetadataEnricher {
24		return &MetadataEnricher{git: git, metrics: metrics}
25	}
26	
27	// EnrichNewSession resolves git metadata and computes initial metrics for a
28	// newly created session. It prefers CWD from the event (set by process
29	// scanner), falling back to transcript inspection for file-based sessions.
30	func (e *MetadataEnricher) EnrichNewSession(state *session.SessionState, ev agent.Event) {
31		// Resolve git metadata.
32		if ev.CWD != "" {
33			state.CWD = ev.CWD
34			state.GitBranch = e.git.GetBranch(ev.CWD)
35			state.ProjectName = e.git.GetProjectName(ev.CWD)
36		} else if ev.TranscriptPath != "" {
37			if cwd := e.git.GetCWDFromTranscript(ev.TranscriptPath); cwd != "" {
38				state.CWD = cwd
39				state.GitBranch = e.git.GetBranch(cwd)
40				state.ProjectName = e.git.GetProjectName(cwd)
41			} else if b := e.git.GetBranchFromTranscript(ev.TranscriptPath); b != "" {
42				state.GitBranch = b
43			}
44		}
45	
46		// Compute initial metrics (no-op for pre-sessions with no transcript).
47		if m, _ := e.metrics.ComputeMetrics(ev.TranscriptPath, ev.Adapter); m != nil {
48			state.Metrics = m
49		}
50	}
51	
52	// RefreshOnActivity refreshes CWD/branch/project from the latest transcript
53	// content and recomputes metrics. A single transcript read serves both metrics
54	// and CWD extraction, eliminating the redundant 32KB read that
55	// GetCWDFromTranscript would perform.
56	func (e *MetadataEnricher) RefreshOnActivity(state *session.SessionState, transcriptPath string) {
57		// Refresh metrics first — the tailer now extracts LastCWD during parsing,
58		// so we get CWD for free without a separate file read.
59		var metricsCWD string
60		if m, _ := e.metrics.ComputeMetrics(transcriptPath, state.Adapter); m != nil {
61			metricsCWD = m.LastCWD
62			state.Metrics = session.MergeMetrics(m, state.Metrics)
63		}
64	
65		// Update CWD from metrics (preferred) or fallback to dedicated read.
66		cwd := metricsCWD
67		if cwd == "" && transcriptPath != "" {
68			cwd = e.git.GetCWDFromTranscript(transcriptPath)
69		}
70		if cwd != "" && cwd != state.CWD {
71			state.CWD = cwd
72			state.GitBranch = e.git.GetBranch(cwd)
73			// Only update ProjectName when the new CWD is inside a git repo.
74			// For non-git directories, keep the original project name set at
75			// session creation to avoid subdirectory names overriding it.
76			// However, if ProjectName was never set (initial enrichment failed
77			// because the transcript was too new), use the full fallback chain.
78			if gitRoot := e.git.GetGitRoot(cwd); gitRoot != "" {
79				state.ProjectName = filepath.Base(gitRoot)
80			} else if state.ProjectName == "" {
81				state.ProjectName = e.git.GetProjectName(cwd)
82			}
83		}
84	}
85	
86	// RefreshMetrics recomputes metrics from the transcript without touching
87	// CWD/branch/project. Used during startup re-evaluation of persisted states.
88	func (e *MetadataEnricher) RefreshMetrics(state *session.SessionState) {
89		if state.TranscriptPath == "" {
90			return
91		}
92		if m, _ := e.metrics.ComputeMetrics(state.TranscriptPath, state.Adapter); m != nil {
93			state.Metrics = session.MergeMetrics(m, state.Metrics)
94		}
95	}
96	
97	// BackfillMetadata fills in missing ProjectName, CWD, and GitBranch for
98	// sessions saved before these fields were populated. Returns the list of
99	// states that were updated (caller is responsible for persisting and
100	// broadcasting).
101	func (e *MetadataEnricher) BackfillMetadata(states []*session.SessionState) []*session.SessionState {
102		var changed []*session.SessionState
103		for _, state := range states {
104			if state.ProjectName != "" {
105				continue
106			}
107			updated := false
108			if state.CWD == "" && state.TranscriptPath != "" {
109				if cwd := e.git.GetCWDFromTranscript(state.TranscriptPath); cwd != "" {
110					state.CWD = cwd
111					updated = true
112				}
113			}
114			if state.CWD != "" {
115				if state.ProjectName == "" {
116					state.ProjectName = e.git.GetProjectName(state.CWD)
117					updated = true
118				}
119				if state.GitBranch == "" {
120					state.GitBranch = e.git.GetBranch(state.CWD)
121					updated = true
122				}
123			}
124			if updated {
125				changed = append(changed, state)
126			}
127		}
128		return changed
129	}
