1	// PIDManager handles process lifecycle for sessions: CWD-based PID discovery,
2	// ProcessWatcher registration, exit handling, and periodic liveness sweeps.
3	// It was extracted from SessionDetector to separate process management from
4	// session detection.
5	package services
6	
7	import (
8		"context"
9		"fmt"
10		"strings"
11		"sync"
12		"sync/atomic"
13		"syscall"
14		"time"
15	
16		"irrlicht/core/domain/lifecycle"
17		"irrlicht/core/domain/session"
18		"irrlicht/core/ports/outbound"
19	)
20	
21	// PIDDiscoverFunc discovers the PID owning a session. Each adapter provides
22	// its own implementation (e.g. CWD-based for Claude Code, transcript-writer
23	// for Codex/Pi). The disambiguate callback selects one PID when multiple
24	// candidates match.
25	type PIDDiscoverFunc func(cwd, transcriptPath string, disambiguate func([]int) int) (int, error)
26	
27	// PIDManager manages the process lifecycle for sessions. It discovers PIDs,
28	// registers them with ProcessWatcher, handles exits, and sweeps dead processes.
29	type PIDManager struct {
30		pw          outbound.ProcessWatcher    // optional — nil disables PID tracking
31		repo        outbound.SessionRepository // shared with SessionDetector
32		log         outbound.Logger
33		broadcaster outbound.PushBroadcaster // optional
34		readyTTL    time.Duration            // max idle time for ready sessions
35	
36		// pidDiscovers maps adapter name → PID discovery function.
37		// Nil or missing entry means no PID discovery for that adapter.
38		pidDiscovers map[string]PIDDiscoverFunc
39	
40		// onSessionDeleted is called when a session is deleted so the caller can
41		// clean up its own tracking structures (e.g. projectSessions map).
42		onSessionDeleted func(sessionID string)
43	
44		// onChildDeleted is called when a child session is removed by the
45		// liveness sweep so the SessionDetector can re-evaluate the parent.
46		// Without this the parent can be left stuck in `working` forever
47		// when it was being held active solely because of the just-deleted
48		// child (see hasActiveChildren in session_detector.go).
49		onChildDeleted func(parentID string)
50	
51		// pendingPIDs stores PIDs discovered by background goroutines, to be
52		// applied by processActivity on its next run. This avoids a race where
53		// HandlePIDAssigned's load-modify-save overwrites a state transition
54		// made by processActivity (e.g. working → ready).
55		pendingMu   sync.Mutex
56		pendingPIDs map[string]int
57	
58		// recorder captures lifecycle events for offline replay (optional).
59		// Set by SessionDetector.SetRecorder.
60		recorder    outbound.EventRecorder
61		recorderSeq *int64 // shared with SessionDetector for monotonic ordering
62	}
