64	// NewPIDManager creates a PIDManager with the given dependencies.
65	// pw and broadcaster may be nil (optional).
66	func NewPIDManager(
67		pw outbound.ProcessWatcher,
68		repo outbound.SessionRepository,
69		log outbound.Logger,
70		broadcaster outbound.PushBroadcaster,
71		readyTTL time.Duration,
72		pidDiscovers map[string]PIDDiscoverFunc,
73		onSessionDeleted func(sessionID string),
74	) *PIDManager {
75		return &PIDManager{
76			pw:               pw,
77			repo:             repo,
78			log:              log,
79			broadcaster:      broadcaster,
80			readyTTL:         readyTTL,
81			pidDiscovers:     pidDiscovers,
82			onSessionDeleted: onSessionDeleted,
83			pendingPIDs:      make(map[string]int),
84		}
85	}
