87	// SetRecorder enables lifecycle event recording on this PIDManager.
88	// The shared sequence counter ensures monotonic ordering across the
89	// SessionDetector and PIDManager.
90	func (pm *PIDManager) SetRecorder(r outbound.EventRecorder, seq *int64) {
91		pm.recorder = r
92		pm.recorderSeq = seq
93	}
94	
95	// SetChildDeletedHandler registers a callback invoked whenever a child
96	// session is deleted by the liveness sweep. The parent's ID is passed so
97	// the caller can re-evaluate the parent, which may have been held in
98	// `working` solely because of that child.
99	func (pm *PIDManager) SetChildDeletedHandler(fn func(parentID string)) {
100		pm.onChildDeleted = fn
101	}
