103	// record emits a lifecycle event if recording is enabled.
104	func (pm *PIDManager) record(ev lifecycle.Event) {
105		if pm.recorder == nil {
106			return
107		}
108		if pm.recorderSeq != nil {
109			ev.Seq = atomic.AddInt64(pm.recorderSeq, 1)
110		}
111		if ev.Timestamp.IsZero() {
112			ev.Timestamp = time.Now()
113		}
114		pm.recorder.Record(ev)
115	}
