117	// HandleProcessExit deletes a session when its process exits.
118	func (pm *PIDManager) HandleProcessExit(pid int, sessionID string) {
119		pm.record(lifecycle.Event{Kind: lifecycle.KindProcessExited, SessionID: sessionID, PID: pid})
120	
121		if pm.onSessionDeleted != nil {
122			pm.onSessionDeleted(sessionID)
123		}
124	
125		state, err := pm.repo.Load(sessionID)
126		if err != nil || state == nil {
127			pm.log.LogInfo("process-exit", sessionID,
128				fmt.Sprintf("pid %d exited but session not found (already cleaned up)", pid))
129			return
130		}
131	
132		pm.log.LogInfo("process-exit", sessionID,
133			fmt.Sprintf("pid %d exited, deleting session (was %s)", pid, state.State))
134	
135		pm.deleteWithChildren(state)
136	}
