138	// deleteWithChildren removes a session and all its child sessions (subagents).
139	func (pm *PIDManager) deleteWithChildren(state *session.SessionState) {
140		if states, err := pm.repo.ListAll(); err == nil {
141			for _, s := range states {
142				if s.ParentSessionID == state.SessionID {
143					_ = pm.repo.Delete(s.SessionID)
144					pm.broadcast(outbound.PushTypeDeleted, s)
145				}
146			}
147		}
148		_ = pm.repo.Delete(state.SessionID)
149		pm.broadcast(outbound.PushTypeDeleted, state)
150	}
