152	// cleanupChildren removes all child sessions of the given parent.
153	func (pm *PIDManager) cleanupChildren(parentID string) {
154		states, err := pm.repo.ListAll()
155		if err != nil {
156			return
157		}
158		for _, s := range states {
159			if s.ParentSessionID == parentID {
160				_ = pm.repo.Delete(s.SessionID)
161				pm.broadcast(outbound.PushTypeDeleted, s)
162			}
163		}
164	}
