166	// HandlePIDAssigned records a newly-discovered PID for a session, registers it
167	// with the ProcessWatcher, and cleans up old sessions that shared the same PID.
168	//
169	// The PID is saved directly to the repo AND stored as a pending PID. The direct
170	// save ensures the PID is persisted even if no subsequent processActivity call
171	// happens. The pending PID is a safety net: if this direct save races with a
172	// concurrent processActivity and overwrites a state transition (e.g. working →
173	// ready), the next processActivity call will consume the pending PID and
174	// re-classify the state correctly.
175	func (pm *PIDManager) HandlePIDAssigned(pid int, sessionID string) {
176		if pid <= 0 {
177			return
178		}
179	
180		pm.record(lifecycle.Event{Kind: lifecycle.KindPIDDiscovered, SessionID: sessionID, PID: pid})
181	
182		// Store pending PID FIRST so processActivity can correct any stale state
183		// that our direct save below might overwrite.
184		pm.pendingMu.Lock()
185		pm.pendingPIDs[sessionID] = pid
186		pm.pendingMu.Unlock()
187	
188		// Load latest state and save PID directly for immediate persistence.
189		state, _ := pm.repo.Load(sessionID)
190		if state == nil || state.PID == pid {
191			return
192		}
193	
194		state.PID = pid
195		state.UpdatedAt = time.Now().Unix()
196		_ = pm.repo.Save(state)
197	
198		// Register with ProcessWatcher for exit monitoring.
199		if pm.pw != nil {
200			if err := pm.pw.Watch(pid, sessionID); err != nil {
201				pm.log.LogError("session-detector", sessionID,
202					fmt.Sprintf("failed to watch pid %d: %v", pid, err))
203			}
204		}
205	
206		// Subagent sessions share the parent's PID, so skip cleanup when
207		// either side is a subagent.
208		if state.ParentSessionID != "" {
209			return
210		}
211	
212		// Clean up old sessions that had the same PID (e.g. /clear).
213		// A non-subagent PID can only belong to one session at a time —
214		// if a new session claims a PID, the old one is stale.
215		states, err := pm.repo.ListAll()
216		if err != nil {
217			return
218		}
219	
220		for _, old := range states {
221			if old.SessionID == sessionID || old.PID != pid {
222				continue
223			}
224			if old.ParentSessionID != "" {
225				continue
226			}
227	
228			pm.log.LogInfo("session-detector", old.SessionID,
229				fmt.Sprintf("replaced by new session %s (same pid %d) — deleting", sessionID, pid))
230	
231			if pm.onSessionDeleted != nil {
232				pm.onSessionDeleted(old.SessionID)
233			}
234	
235			_ = pm.repo.Delete(old.SessionID)
236			pm.broadcast(outbound.PushTypeDeleted, old)
237		}
238	}
