240	// ConsumePendingPID returns and removes a pending PID for the given session.
241	// Called by processActivity to atomically apply PID assignment during the
242	// normal state-update flow, avoiding the race with direct Save.
243	func (pm *PIDManager) ConsumePendingPID(sessionID string) (int, bool) {
244		pm.pendingMu.Lock()
245		defer pm.pendingMu.Unlock()
246		pid, ok := pm.pendingPIDs[sessionID]
247		if ok {
248			delete(pm.pendingPIDs, sessionID)
249		}
250		return pid, ok
251	}
