253	// claimedPIDs returns the set of PIDs already assigned to sessions other than
254	// excludeSessionID.
255	func (pm *PIDManager) claimedPIDs(excludeSessionID string) map[int]bool {
256		states, err := pm.repo.ListAll()
257		if err != nil {
258			return nil
259		}
260		claimed := make(map[int]bool)
261		for _, s := range states {
262			if s.PID > 0 && s.SessionID != excludeSessionID {
263				claimed[s.PID] = true
264			}
265		}
266		return claimed
267	}
