269	// TryDiscoverPID finds the PID for a session using the adapter-specific
270	// discovery function. Prefers unclaimed PIDs but falls back to already-
271	// claimed PIDs when no unclaimed candidate exists (the /clear scenario where
272	// the same process starts a new transcript). Returns true if a PID was found.
273	func (pm *PIDManager) TryDiscoverPID(sessionID, cwd, transcriptPath, adapter string) bool {
274		if pm.pw == nil {
275			return false
276		}
277		discoverFn := pm.pidDiscovers[adapter]
278		if discoverFn == nil {
279			return false
280		}
281		// Check if session already has a PID.
282		state, _ := pm.repo.Load(sessionID)
283		if state != nil && state.PID > 0 {
284			return true
285		}
286	
287		// Prefer unclaimed PIDs (multiple instances in same dir), but allow
288		// claimed PIDs when all candidates are claimed (/clear scenario).
289		claimed := pm.claimedPIDs(sessionID)
290		disambiguate := func(pids []int) int {
291			bestUnclaimed, bestAny := 0, 0
292			for _, p := range pids {
293				if p > bestAny {
294					bestAny = p
295				}
296				if !claimed[p] && p > bestUnclaimed {
297					bestUnclaimed = p
298				}
299			}
300			if bestUnclaimed > 0 {
301				return bestUnclaimed
302			}
303			return bestAny
304		}
305	
306		if pid, err := discoverFn(cwd, transcriptPath, disambiguate); err == nil && pid > 0 {
307			pm.log.LogInfo("session-detector", sessionID,
308				fmt.Sprintf("discovered pid %d for %s session", pid, adapter))
309			pm.HandlePIDAssigned(pid, sessionID)
310			return true
311		}
312		return false
313	}
