315	// DiscoverPIDWithRetry tries to discover a PID immediately, then retries at
316	// 500ms, 1s, 2s intervals. This covers the timing where the agent process
317	// hasn't started yet or the transcript file isn't open yet.
318	func (pm *PIDManager) DiscoverPIDWithRetry(sessionID, cwd, transcriptPath, adapter string) {
319		if pm.TryDiscoverPID(sessionID, cwd, transcriptPath, adapter) {
320			return
321		}
322		for _, delay := range []time.Duration{500 * time.Millisecond, 1 * time.Second, 2 * time.Second} {
323			time.Sleep(delay)
324			state, _ := pm.repo.Load(sessionID)
325			if state == nil || state.PID > 0 {
326				return
327			}
328			if pm.TryDiscoverPID(sessionID, cwd, transcriptPath, adapter) {
329				return
330			}
331		}
332	}
