334	// SweepDeadPIDs periodically checks all sessions for dead processes and deletes
335	// them. This is a safety net for cases where kqueue misses an exit (PID not
336	// registered, daemon restart window, race conditions). Blocks until ctx is
337	// cancelled. The sweep interval backs off from 5s to 15s when no dead PIDs
338	// are found for several consecutive sweeps.
339	func (pm *PIDManager) SweepDeadPIDs(ctx context.Context) {
340		const baseInterval = 5 * time.Second
341		const backoffInterval = 15 * time.Second
342		const cleanThreshold = 3
343	
344		ticker := time.NewTicker(baseInterval)
345		defer ticker.Stop()
346	
347		cleanSweeps := 0
348		currentInterval := baseInterval
349	
350		for {
351			select {
352			case <-ctx.Done():
353				return
354			case <-ticker.C:
355				foundDead := pm.CheckPIDLiveness()
356	
357				if foundDead {
358					cleanSweeps = 0
359				} else {
360					cleanSweeps++
361				}
362	
363				var targetInterval time.Duration
364				if cleanSweeps >= cleanThreshold {
365					targetInterval = backoffInterval
366				} else {
367					targetInterval = baseInterval
368				}
369				if targetInterval != currentInterval {
370					ticker.Reset(targetInterval)
371					currentInterval = targetInterval
372				}
373			}
374		}
375	}
