377	// CheckPIDLiveness checks all sessions for dead PIDs and stale state.
378	// Returns true if any dead PID was found and cleaned up.
379	func (pm *PIDManager) CheckPIDLiveness() bool {
380		states, err := pm.repo.ListAll()
381		if err != nil {
382			return false
383		}
384		foundDead := false
385		for _, state := range states {
386			if state.PID > 0 {
387				if err := syscall.Kill(state.PID, 0); err == syscall.ESRCH {
388					pm.HandleProcessExit(state.PID, state.SessionID)
389					foundDead = true
390				}
391			}
392		}
393	
394		// Sweep stale sessions that can't be cleaned up via PID liveness:
395		// - Ready sessions (idle beyond TTL)
396		// - Working/waiting sessions with PID=0 (zombies where PID discovery
397		//   failed and no kqueue/sweep cleanup path can fire)
398		// - Child sessions: ready or stale transcript (finished/zombie subagents)
399		if pm.readyTTL > 0 {
400			for _, state := range states {
401				// Child sessions: clean up immediately when ready, or when stale
402				// (transcript stopped updating — zombie from a previous run).
403				if state.ParentSessionID != "" {
404					if state.State == session.StateReady || isStaleTranscript(state.TranscriptPath) {
405						parentID := state.ParentSessionID
406						_ = pm.repo.Delete(state.SessionID)
407						pm.broadcast(outbound.PushTypeDeleted, state)
408						// Re-evaluate the parent: it may have been held in
409						// `working` only because of this child. Without this
410						// nudge the parent stays stuck until its own next
411						// transcript event, which may never come for a
412						// finished session.
413						if pm.onChildDeleted != nil {
414							pm.onChildDeleted(parentID)
415						}
416					}
417					continue
418				}
419				// Sessions with PID=0 that are ready: the process likely exited
420				// before PID discovery succeeded. Clean up quickly (30s) rather
421				// than waiting the full readyTTL — BUT only if the transcript
422				// itself is stale. A freshly-written transcript with no PID
423				// yet means PID discovery is still catching up (e.g. Claude
424				// hasn't written ~/.claude/sessions/<pid>.json yet, or multiple
425				// claude processes share a cwd and the metadata lookup is
426				// retrying). Deleting under those conditions causes the flap
427				// loop in issue #109.
428				if state.PID == 0 && state.State == session.StateReady &&
429					time.Since(time.Unix(state.UpdatedAt, 0)) > 30*time.Second &&
430					isStaleTranscript(state.TranscriptPath) {
431					pm.log.LogInfo("session-detector", state.SessionID,
432						"ready session with no PID and stale transcript for >30s, deleting")
433					pm.deleteWithChildren(state)
434					continue
435				}
436	
437				if !state.IsStale(pm.readyTTL) {
438					continue
439				}
440				// Don't delete sessions whose process is still alive.
441				if state.PID > 0 {
442					if err := syscall.Kill(state.PID, 0); err == nil {
443						continue
444					}
445				}
446				if state.State == session.StateReady || state.PID == 0 {
447					pm.log.LogInfo("session-detector", state.SessionID,
448						fmt.Sprintf("%s session (pid=%d) idle for >%v, deleting",
449							state.State, state.PID, pm.readyTTL))
450					pm.deleteWithChildren(state)
451				}
452			}
453		}
454		return foundDead
455	}
