457	// SeedPIDs cleans up dead sessions and registers alive PIDs with ProcessWatcher
458	// during startup. Called from SessionDetector.seedFromDisk.
459	func (pm *PIDManager) SeedPIDs(states []*session.SessionState) {
460		// Track the newest session per PID for deduplication.
461		newestByPID := make(map[int]*session.SessionState)
462	
463		for _, state := range states {
464			switch {
465			case state.PID > 0:
466				if err := syscall.Kill(state.PID, 0); err == syscall.ESRCH {
467					pm.log.LogInfo("session-detector-seed", state.SessionID,
468						fmt.Sprintf("pid %d dead, deleting session", state.PID))
469					pm.deleteWithChildren(state)
470					continue
471				}
472				if pm.pw != nil {
473					if err := pm.pw.Watch(state.PID, state.SessionID); err != nil {
474						pm.log.LogError("session-detector-seed", state.SessionID,
475							fmt.Sprintf("failed to watch existing pid %d: %v", state.PID, err))
476					}
477				}
478	
479				// Track newest non-subagent session per PID for dedup below.
480				if state.ParentSessionID == "" && !strings.HasPrefix(state.SessionID, "proc-") {
481					if prev, ok := newestByPID[state.PID]; !ok || state.FirstSeen > prev.FirstSeen {
482						newestByPID[state.PID] = state
483					}
484				}
485	
486			case state.PID == 0 && state.ParentSessionID == "" && isStaleTranscript(state.TranscriptPath):
487				// Orphan from exited process (PID discovery never succeeded).
488				// Child sessions (ParentSessionID set) are exempt — they run
489				// inside the parent process and never get their own PID.
490				pm.log.LogInfo("session-detector-seed", state.SessionID,
491					"deleting orphan session")
492				pm.deleteWithChildren(state)
493			}
494		}
495	
496		// Deduplicate: when multiple non-subagent sessions share a PID (e.g.
497		// orphans left by /clear), keep only the newest one.
498		for pid, newest := range newestByPID {
499			for _, state := range states {
500				if state.PID != pid || state.SessionID == newest.SessionID {
501					continue
502				}
503				if state.ParentSessionID != "" || strings.HasPrefix(state.SessionID, "proc-") {
504					continue
505				}
506				// Verify session still exists (may have been deleted above).
507				if s, _ := pm.repo.Load(state.SessionID); s == nil {
508					continue
509				}
510				pm.log.LogInfo("session-detector-seed", state.SessionID,
511					fmt.Sprintf("duplicate pid %d (keeping %s) — deleting", pid, newest.SessionID))
512	
513				if pm.onSessionDeleted != nil {
514					pm.onSessionDeleted(state.SessionID)
515				}
516				_ = pm.repo.Delete(state.SessionID)
517				pm.broadcast(outbound.PushTypeDeleted, state)
518			}
519		}
520	
521		// Clean up stale pre-sessions (proc-*) that have a corresponding real
522		// session. Match by PID (preferred) or by adapter + CWD (for adapters
523		// like Codex whose PID discovery may not have completed yet).
524		for _, proc := range states {
525			if !strings.HasPrefix(proc.SessionID, "proc-") {
526				continue
527			}
528			if s, _ := pm.repo.Load(proc.SessionID); s == nil {
529				continue // already deleted above
530			}
531			for _, candidate := range states {
532				if strings.HasPrefix(candidate.SessionID, "proc-") || candidate.TranscriptPath == "" {
533					continue
534				}
535				matched := proc.PID > 0 && proc.PID == candidate.PID
536				if !matched && proc.CWD != "" && proc.Adapter == candidate.Adapter && proc.CWD == candidate.CWD {
537					matched = true
538				}
539				if matched {
540					pm.log.LogInfo("session-detector-seed", proc.SessionID,
541						fmt.Sprintf("pre-session superseded by %s — deleting", candidate.SessionID))
542					if pm.onSessionDeleted != nil {
543						pm.onSessionDeleted(proc.SessionID)
544					}
545					_ = pm.repo.Delete(proc.SessionID)
546					pm.broadcast(outbound.PushTypeDeleted, proc)
547					break
548				}
549			}
550		}
551	}
