553	// broadcast sends a push notification if a broadcaster is configured.
554	func (pm *PIDManager) broadcast(msgType string, state *session.SessionState) {
555		if pm.broadcaster != nil {
556			pm.broadcaster.Broadcast(outbound.PushMessage{Type: msgType, Session: state})
557		}
